import{_ as e,o as i,c as l,a5 as t}from"./chunks/framework.D9Kapg2s.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/faq.md","filePath":"zh/guide/faq.md"}'),o={name:"zh/guide/faq.md"};function r(d,a,s,h,n,c){return i(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>按「第一次卡住 → 配置 → 质量 → 格式 → 数据」排序。更完整的安装与模式说明见 <a href="/zh/guide/installation.html">安装部署</a>、<a href="/zh/guide/modes.html">使用模式</a>。</p><h2 id="第一次使用" tabindex="-1">第一次使用 <a class="header-anchor" href="#第一次使用" aria-label="Permalink to &quot;第一次使用&quot;">​</a></h2><h3 id="应该用二进制还是-docker-端口是多少" tabindex="-1">应该用二进制还是 Docker？端口是多少？ <a class="header-anchor" href="#应该用二进制还是-docker-端口是多少" aria-label="Permalink to &quot;应该用二进制还是 Docker？端口是多少？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>模式</th><th>默认地址</th><th>说明</th></tr></thead><tbody><tr><td>预编译二进制 / 双击</td><td>本地模式</td><td><code>http://127.0.0.1:18080</code></td><td><strong>个人推荐</strong>，免登录</td></tr><tr><td>Docker 默认</td><td>服务器模式（预览）</td><td><code>http://localhost:8080</code></td><td>需注册/登录</td></tr></tbody></table><p>个人试用请优先二进制本地模式。详见 <a href="/zh/guide/installation.html">安装部署</a> 与 <a href="/zh/guide/modes.html">使用模式</a>。</p><h3 id="双击-启动后浏览器没打开" tabindex="-1">双击 / 启动后浏览器没打开？ <a class="header-anchor" href="#双击-启动后浏览器没打开" aria-label="Permalink to &quot;双击 / 启动后浏览器没打开？&quot;">​</a></h3><ol><li>手动访问 <code>http://127.0.0.1:18080</code>（若被占用，终端日志里会打印实际端口）</li><li>确认进程仍在运行，终端无立即退出</li><li>若使用了 <code>--no-browser</code>，需自行打开浏览器</li><li>公司代理 / 安全软件可能拦截本机回环访问，可换浏览器或检查系统代理例外</li></ol><h3 id="打开界面后是空白页-一直转圈" tabindex="-1">打开界面后是空白页 / 一直转圈？ <a class="header-anchor" href="#打开界面后是空白页-一直转圈" aria-label="Permalink to &quot;打开界面后是空白页 / 一直转圈？&quot;">​</a></h3><ol><li>硬刷新（Ctrl+F5）或换一个浏览器</li><li>确认访问的是日志中的地址与端口，不要混用 <code>18080</code>（本地）与 <code>8080</code>（Docker/serve）</li><li>查看启动终端是否有报错</li><li>从源码开发时，需前后端都起来；预编译二进制则 UI 已嵌入，一般只需一个进程</li></ol><h3 id="第一次使用必须创建很复杂的执行计划吗" tabindex="-1">第一次使用必须创建很复杂的执行计划吗？ <a class="header-anchor" href="#第一次使用必须创建很复杂的执行计划吗" aria-label="Permalink to &quot;第一次使用必须创建很复杂的执行计划吗？&quot;">​</a></h3><p>不需要。先建 <strong>单轮翻译</strong>：选择你的 AI 后端 + 内置「通用提示词」+ 内置「通用策略」，批次与并发用较小值即可。术语提取、质量裁决等可在跑通后再加。见 <a href="/zh/guide/getting-started.html">快速开始 · Web</a> 与 <a href="/zh/guide/concepts.html">核心概念</a>。</p><h3 id="执行计划是什么-为什么不能直接点翻译" tabindex="-1">执行计划是什么？为什么不能直接点翻译？ <a class="header-anchor" href="#执行计划是什么-为什么不能直接点翻译" aria-label="Permalink to &quot;执行计划是什么？为什么不能直接点翻译？&quot;">​</a></h3><p><strong>执行计划</strong>告诉系统：用哪个 AI 后端、哪套提示词与策略、要跑几轮（翻译 / 术语提取 / 质量裁决）。<br> Web 里点「翻译」时必须选一份计划，因为服务端不会替你猜 API Key 与模型。<br> 最短做法：只建一轮 <code>translate</code>，绑定你的后端与内置模板。说明见 <a href="/zh/guide/concepts.html#执行计划为什么重要">核心概念 · 执行计划</a>。</p><h3 id="点「开始翻译」没反应或作业立刻失败" tabindex="-1">点「开始翻译」没反应或作业立刻失败？ <a class="header-anchor" href="#点「开始翻译」没反应或作业立刻失败" aria-label="Permalink to &quot;点「开始翻译」没反应或作业立刻失败？&quot;">​</a></h3><p>按顺序排查：</p><ol><li><strong>是否选了执行计划</strong>，且计划里绑定的后端仍存在</li><li><strong>API Key</strong> 是否有效、余额/配额是否够用</li><li>作业详情中的 <strong>错误信息</strong>（401/403 多为密钥或权限；429 为限速）</li><li>网络是否能访问对应 API / Base URL（公司防火墙、需代理时）</li><li>首次建议 <code>batch_size = 1</code>、并发 <code>2</code>，排除批次过大导致的解析失败</li></ol><p>仍失败时加 CLI <code>-v</code> 或查看服务日志，并到 <a href="https://github.com/MeowSalty/LinguaFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 搜索同类问题。</p><h3 id="docker-启动后无法访问" tabindex="-1">Docker 启动后无法访问？ <a class="header-anchor" href="#docker-启动后无法访问" aria-label="Permalink to &quot;Docker 启动后无法访问？&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 确认容器正在运行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linguaflow</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 查看日志</span></span></code></pre></div><ul><li>端口映射应为 <strong>8080</strong>（例：<code>-p 8080:8080</code>）</li><li>浏览器访问 <code>http://localhost:8080</code></li><li>Docker 默认是 <strong>服务器模式</strong>，需要注册/登录，不是本地模式的免登录体验</li><li>检查本机防火墙与端口占用</li></ul><h3 id="从源码构建失败" tabindex="-1">从源码构建失败？ <a class="header-anchor" href="#从源码构建失败" aria-label="Permalink to &quot;从源码构建失败？&quot;">​</a></h3><ol><li>确认 Go 版本 &gt;= 1.21</li><li>确认 Node.js 版本 &gt;= 20</li><li>确认已安装 pnpm 与 <a href="https://taskfile.dev" target="_blank" rel="noreferrer">Task</a></li><li>运行 <code>task backend:install</code> 和 <code>task frontend:install</code> 安装依赖</li><li>按 <a href="/zh/guide/installation.html#从源码构建">安装部署 · 从源码构建</a> 完整步骤构建</li></ol><h2 id="ai-后端配置" tabindex="-1">AI 后端配置 <a class="header-anchor" href="#ai-后端配置" aria-label="Permalink to &quot;AI 后端配置&quot;">​</a></h2><h3 id="api-key-无效" tabindex="-1">API Key 无效？ <a class="header-anchor" href="#api-key-无效" aria-label="Permalink to &quot;API Key 无效？&quot;">​</a></h3><ul><li>确认 API Key 是否正确复制（无多余空格、无缺段）</li><li>确认 Key 未过期、未被禁用，且账号有权限调用所选模型</li><li>使用自定义 <strong>Base URL</strong> 时，确认路径是否要求 <code>/v1</code> 等后缀</li><li>环境变量引用（如 <code>\${OPENAI_API_KEY}</code>）在进程启动前是否已 export</li></ul><h3 id="翻译速度很慢" tabindex="-1">翻译速度很慢？ <a class="header-anchor" href="#翻译速度很慢" aria-label="Permalink to &quot;翻译速度很慢？&quot;">​</a></h3><ul><li>检查到 AI 服务的网络延迟与带宽</li><li>换更小/更快的模型做草稿</li><li>适当增大批次（短段）或降低并发（避免 429 重试拖慢）</li><li>减少上下文窗口（<code>context.before</code> / <code>after</code>）</li><li>检查后端是否配置了过严的 <code>rate_limit_per_minute</code></li></ul><h3 id="翻译质量不理想" tabindex="-1">翻译质量不理想？ <a class="header-anchor" href="#翻译质量不理想" aria-label="Permalink to &quot;翻译质量不理想？&quot;">​</a></h3><ul><li>启用并维护 <strong>术语表</strong></li><li>调整或自定义提示词模板</li><li>指定明确的源/目标语言，避免关键场景下 <code>auto</code> 误判</li><li>尝试不同模型；关键内容可用多轮计划提高成功率</li><li>开启质量检测，必要时加 <strong>AI 质量裁决</strong> 降噪后再人工审校</li></ul><h3 id="兼容网关要求-stream-true" tabindex="-1">兼容网关要求 stream:true？ <a class="header-anchor" href="#兼容网关要求-stream-true" aria-label="Permalink to &quot;兼容网关要求 stream:true？&quot;">​</a></h3><p>在 AI 后端选项中开启 <strong>流式请求</strong>（<code>stream: true</code>）。请求以流式发起，服务端内部累积为完整响应后再处理，对外行为不变。OpenAI / Anthropic / Google 三类后端均支持。</p><h3 id="频繁-429-速率限制" tabindex="-1">频繁 429 / 速率限制？ <a class="header-anchor" href="#频繁-429-速率限制" aria-label="Permalink to &quot;频繁 429 / 速率限制？&quot;">​</a></h3><ul><li>降低执行计划中的 <strong>并发</strong>（先试 <code>1</code>～<code>2</code>）</li><li>减小批次或拉长重试退避</li><li>在后端设置合理的 <code>rate_limit_per_minute</code></li><li>确认云厂商控制台的 RPM/TPM 配额</li></ul><h3 id="源语残留误报很多" tabindex="-1">源语残留误报很多？ <a class="header-anchor" href="#源语残留误报很多" aria-label="Permalink to &quot;源语残留误报很多？&quot;">​</a></h3><p>源语残留检测偏敏感（专有名词、代码、刻意保留原文等可能被标出）。可：</p><ol><li>在执行计划中增加 <strong>质量裁决</strong>（<code>adjudicate</code>）轮次，对 <code>source_residual</code> 做 AI 复核（见 <a href="/zh/guide/pipeline.html#规则质检与-ai-质量裁决">流水线与原理</a>）</li><li>在段落列表中按 <code>source_residual</code> 筛选后人工确认</li><li>确保项目源语言不是 <code>auto</code>（<code>auto</code> 时残留检测不生效，但指定错误语言也会影响规则）</li></ol><h2 id="文件格式" tabindex="-1">文件格式 <a class="header-anchor" href="#文件格式" aria-label="Permalink to &quot;文件格式&quot;">​</a></h2><h3 id="支持哪些格式" tabindex="-1">支持哪些格式？ <a class="header-anchor" href="#支持哪些格式" aria-label="Permalink to &quot;支持哪些格式？&quot;">​</a></h3><p>Markdown、HTML、DOCX、EPUB、SRT/VTT/ASS 字幕、JSON/YAML/TOML、纯文本等。详见 <a href="/zh/guide/formats.html">格式支持</a>。</p><h3 id="epub-翻译后排版混乱" tabindex="-1">EPUB 翻译后排版混乱？ <a class="header-anchor" href="#epub-翻译后排版混乱" aria-label="Permalink to &quot;EPUB 翻译后排版混乱？&quot;">​</a></h3><ul><li>确认 EPUB 文件格式是否标准、无 DRM</li><li>尝试按章节分批翻译</li><li>检查是否有特殊格式需要保护</li><li>用阅读器打开导出文件核对样式</li></ul><h3 id="docx-部分内容未翻译" tabindex="-1">DOCX 部分内容未翻译？ <a class="header-anchor" href="#docx-部分内容未翻译" aria-label="Permalink to &quot;DOCX 部分内容未翻译？&quot;">​</a></h3><p>当前主要处理主文档 <code>word/document.xml</code> 中的段落。页眉页脚、批注、SmartArt、图表等可能不在翻译范围内，翻译后请用 Word 打开校对。</p><h3 id="字幕文件时间码被修改" tabindex="-1">字幕文件时间码被修改？ <a class="header-anchor" href="#字幕文件时间码被修改" aria-label="Permalink to &quot;字幕文件时间码被修改？&quot;">​</a></h3><p>LinguaFlow 会自动保护时间码。若发现时间码被改：</p><ul><li>检查文件编码是否为 UTF-8</li><li>确认扩展名与真实格式一致（<code>.srt</code> / <code>.vtt</code> / <code>.ass</code>）</li><li>避免手工破坏时间码行后再导入</li></ul><h3 id="json-yaml-译坏了结构" tabindex="-1">JSON / YAML 译坏了结构？ <a class="header-anchor" href="#json-yaml-译坏了结构" aria-label="Permalink to &quot;JSON / YAML 译坏了结构？&quot;">​</a></h3><ul><li>确认文件本身可被标准解析器打开</li><li>结构化格式按<strong>字符串叶子</strong>翻译；数字、布尔等一般不译</li><li>YAML/TOML <strong>注释</strong>可能无法保留</li><li>译后用原格式校验器检查；必要时减小批次并重跑失败资源</li></ul><h2 id="数据与存储" tabindex="-1">数据与存储 <a class="header-anchor" href="#数据与存储" aria-label="Permalink to &quot;数据与存储&quot;">​</a></h2><h3 id="数据存储在哪里" tabindex="-1">数据存储在哪里？ <a class="header-anchor" href="#数据存储在哪里" aria-label="Permalink to &quot;数据存储在哪里？&quot;">​</a></h3><ul><li><strong>本地模式</strong> — SQLite，默认在系统用户配置目录下的 <code>LinguaFlow</code>（如 Windows <code>%APPDATA%\\LinguaFlow</code>）</li><li><strong>服务器模式（预览）</strong> — 默认 <code>./data/linguaflow.db</code>；可用 <code>--data-dir</code> 或环境变量指定；PostgreSQL 时库内数据在数据库中，任务/资源相关本地文件仍在数据目录下</li></ul><h3 id="如何备份数据" tabindex="-1">如何备份数据？ <a class="header-anchor" href="#如何备份数据" aria-label="Permalink to &quot;如何备份数据？&quot;">​</a></h3><p>复制 SQLite 数据库文件即可（路径以你的 <code>--data-dir</code> / 本地配置目录为准）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例：服务器模式默认相对路径</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/linguaflow.db</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./backup/linguaflow_backup.db</span></span></code></pre></div><h3 id="如何迁移数据" tabindex="-1">如何迁移数据？ <a class="header-anchor" href="#如何迁移数据" aria-label="Permalink to &quot;如何迁移数据？&quot;">​</a></h3><p>将数据库文件复制到新环境对应数据目录即可。更换机器时注意同时迁移数据目录中的资源文件（若有）。</p><h2 id="性能与限制" tabindex="-1">性能与限制 <a class="header-anchor" href="#性能与限制" aria-label="Permalink to &quot;性能与限制&quot;">​</a></h2><h3 id="支持多大的文件" tabindex="-1">支持多大的文件？ <a class="header-anchor" href="#支持多大的文件" aria-label="Permalink to &quot;支持多大的文件？&quot;">​</a></h3><p>取决于 AI 上下文、可用内存与网络。大 EPUB / 长文档建议按章节或资源分批作业，并配合合理的 <code>batch_size</code> / <code>max_words_per_batch</code>。</p><h3 id="批次大小设多少-要不要用字数限制" tabindex="-1">批次大小设多少？要不要用字数限制？ <a class="header-anchor" href="#批次大小设多少-要不要用字数限制" aria-label="Permalink to &quot;批次大小设多少？要不要用字数限制？&quot;">​</a></h3><ul><li><strong>内置默认</strong>多为 <code>batch_size: 1</code>（稳妥、好排错），对当前大上下文模型来说<strong>偏保守</strong></li><li><strong>日常吞吐</strong>：短段可试 <code>8</code>～<code>20</code> 段/批；普通文档可试 <code>4</code>～<code>10</code></li><li><strong>更推荐</strong>同时设 <code>max_words_per_batch</code>（与 <code>batch_size</code> 双重约束）</li><li>批次过大时更常见 JSON/漏段/占位符问题</li></ul><p>详见 <a href="/zh/guide/getting-started.html#批次怎么设">快速开始 · Web · 批次怎么设</a> 与 <a href="/zh/guide/pipeline.html#批量与并发">流水线与原理 · 批量与并发</a>。</p><h3 id="支持多少并发翻译" tabindex="-1">支持多少并发翻译？ <a class="header-anchor" href="#支持多少并发翻译" aria-label="Permalink to &quot;支持多少并发翻译？&quot;">​</a></h3><p>这里的「并发」是<strong>同一文件内</strong>同时处理的批次数（<code>concurrency</code>），不是多文件并行。</p><ul><li>受 API 速率限制影响大（过高易 429）</li><li>单批越大，并发宜略降</li><li>起步可用 <code>2</code>～<code>4</code>，观察限速与错误后再调</li></ul><h2 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h2><p>如果以上没有解决你的问题：</p><ul><li>查看 <a href="https://github.com/MeowSalty/LinguaFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li><a href="https://github.com/MeowSalty/LinguaFlow/issues/new" target="_blank" rel="noreferrer">提交新 Issue</a> 时请附上：模式（local/serve/Docker）、版本号、<code>linguaflow version</code> 输出、脱敏后的错误日志</li></ul>`,69)])])}const b=e(o,[["render",r]]);export{p as __pageData,b as default};
